   551→			state.Reset()
   552→			return nil, state, nil, err
   553→		}
   554→		// decodeRecord() will return io.EOF if it detects a zero record,
   555→		// but this zero record may be followed by non-zero records from
   556→		// a torn write. Overwriting some of these non-zero records, but
   557→		// not all, will cause CRC errors on WAL open. Since the records
   558→		// were never fully synced to disk in the first place, it's safe
   559→		// to zero them out to avoid any CRC errors from new writes.
   560→		if _, err = w.tail().Seek(w.decoder.LastOffset(), io.SeekStart); err != nil {
   561→			return nil, state, nil, err
   562→		}
   563→		if err = fileutil.ZeroToEnd(w.tail().File); err != nil {
   564→			return nil, state, nil, err
   565→		}
   566→	}
   567→
   568→	err = nil
   569→	if !match {
   570→		err = ErrSnapshotNotFound
   571→	}
   572→
   573→	// close decoder, disable reading
   574→	if w.readClose != nil {
   575→		w.readClose()
   576→		w.readClose = nil
   577→	}
   578→	w.start = walpb.Snapshot{}
   579→
   580→	w.metadata = metadata
   581→
   582→	if w.tail() != nil {
   583→		// create encoder (chain crc with the decoder), enable appending
   584→		w.encoder, err = newFileEncoder(w.tail().File, w.decoder.LastCRC())
   585→		if err != nil {
   586→			return nil, state, nil, err
   587→		}
   588→	}
   589→	w.decoder = nil
   590→
   591→	return metadata, state, ents, err
   592→}
