   594→// ValidSnapshotEntries returns all the valid snapshot entries in the wal logs in the given directory.
   595→// Snapshot entries are valid if their index is less than or equal to the most recent committed hardstate.
   596→func ValidSnapshotEntries(lg *zap.Logger, walDir string) ([]walpb.Snapshot, error) {
   597→	var snaps []walpb.Snapshot
   598→	var state raftpb.HardState
   599→	var err error
   600→
   601→	rec := &walpb.Record{}
   602→	names, err := readWALNames(lg, walDir)
   603→	if err != nil {
   604→		return nil, err
   605→	}
   606→
   607→	// open wal files in read mode, so that there is no conflict
   608→	// when the same WAL is opened elsewhere in write mode
   609→	rs, _, closer, err := openWALFiles(lg, walDir, names, 0, false)
   610→	if err != nil {
   611→		return nil, err
   612→	}
   613→	defer func() {
   614→		if closer != nil {
   615→			closer()
   616→		}
   617→	}()
   618→
   619→	// create a new decoder from the readers on the WAL files
   620→	decoder := NewDecoder(rs...)
   621→
   622→	for err = decoder.Decode(rec); err == nil; err = decoder.Decode(rec) {
   623→		switch rec.GetType() {
   624→		case SnapshotType:
   625→			var loadedSnap walpb.Snapshot
   626→			pbutil.MustUnmarshal(&loadedSnap, rec.Data)
   627→			snaps = append(snaps, loadedSnap)
   628→		case StateType:
   629→			state = MustUnmarshalState(rec.Data)
   630→		case CrcType:
   631→			crc := decoder.LastCRC()
   632→			// current crc of decoder must match the crc of the record.
   633→			// do no need to match 0 crc, since the decoder is a new one at this case.
   634→			if crc != 0 && rec.Validate(crc) != nil {
   635→				return nil, ErrCRCMismatch
   636→			}
   637→			decoder.UpdateCRC(rec.GetCrc())
   638→		}
   639→	}
   640→	// We do not have to read out all the WAL entries
   641→	// as the decoder is opened in read mode.
   642→	if !errors.Is(err, io.EOF) && !errors.Is(err, io.ErrUnexpectedEOF) {
   643→		return nil, err
   644→	}
   645→
   646→	// filter out any snaps that are newer than the committed hardstate
   647→	n := 0
   648→	for _, s := range snaps {
   649→		if s.GetIndex() <= state.Commit {
   650→			snaps[n] = s
   651→			n++
   652→		}
   653→	}
   654→	snaps = snaps[:n:n]
   655→	return snaps, nil
   656→}
   657→
   658→// Verify reads through the given WAL and verifies that it is not corrupted.
   659→// It creates a new decoder to read through the records of the given WAL.
   660→// It does not conflict with any open WAL, but it is recommended not to
   661→// call this function after opening the WAL for writing.
   662→// If it cannot read out the expected snap, it will return ErrSnapshotNotFound.
   663→// If the loaded snap doesn't match with the expected one, it will
   664→// return error ErrSnapshotMismatch.
   665→func Verify(lg *zap.Logger, walDir string, snap walpb.Snapshot) (*raftpb.HardState, error) {
   666→	var metadata []byte
   667→	var err error
   668→	var match bool
   669→	var state raftpb.HardState
   670→
   671→	rec := &walpb.Record{}
   672→
   673→	if lg == nil {
   674→		lg = zap.NewNop()
   675→	}
   676→	names, nameIndex, err := selectWALFiles(lg, walDir, snap)
   677→	if err != nil {
   678→		return nil, err
   679→	}
   680→
   681→	// open wal files in read mode, so that there is no conflict
   682→	// when the same WAL is opened elsewhere in write mode
   683→	rs, _, closer, err := openWALFiles(lg, walDir, names, nameIndex, false)
   684→	if err != nil {
   685→		return nil, err
   686→	}
   687→	defer func() {
   688→		if closer != nil {
   689→			closer()
   690→		}
   691→	}()
   692→
   693→	// create a new decoder from the readers on the WAL files
   694→	decoder := NewDecoder(rs...)
   695→
   696→	for err = decoder.Decode(rec); err == nil; err = decoder.Decode(rec) {
   697→		switch rec.GetType() {
   698→		case MetadataType:
   699→			if metadata != nil && !bytes.Equal(metadata, rec.Data) {
   700→				return nil, ErrMetadataConflict
   701→			}
   702→			metadata = rec.Data
   703→		case CrcType:
   704→			crc := decoder.LastCRC()
   705→			// Current crc of decoder must match the crc of the record.
   706→			// We need not match 0 crc, since the decoder is a new one at this point.
   707→			if crc != 0 && rec.Validate(crc) != nil {
   708→				return nil, ErrCRCMismatch
   709→			}
   710→			decoder.UpdateCRC(rec.GetCrc())
   711→		case SnapshotType:
   712→			var loadedSnap walpb.Snapshot
   713→			pbutil.MustUnmarshal(&loadedSnap, rec.Data)
   714→			if loadedSnap.GetIndex() == snap.GetIndex() {
   715→				if loadedSnap.GetTerm() != snap.GetTerm() {
   716→					return nil, ErrSnapshotMismatch
   717→				}
   718→				match = true
   719→			}
   720→		// We ignore all entry and state type records as these
   721→		// are not necessary for validating the WAL contents
   722→		case EntryType:
   723→		case StateType:
   724→			pbutil.MustUnmarshal(&state, rec.Data)
   725→		default:
   726→			return nil, fmt.Errorf("unexpected block type %d", rec.Type)
   727→		}
   728→	}
   729→
   730→	// We do not have to read out all the WAL entries
   731→	// as the decoder is opened in read mode.
   732→	if !errors.Is(err, io.EOF) && !errors.Is(err, io.ErrUnexpectedEOF) {
   733→		return nil, err
   734→	}
   735→
   736→	if !match {
   737→		return nil, ErrSnapshotNotFound
   738→	}
   739→
   740→	return &state, nil
   741→}
