   301→func bootstrapCluster(cfg config.ServerConfig, bwal *bootstrappedWAL, prt http.RoundTripper) (c *bootstrappedCluster, err error) {
   302→	switch {
   303→	case bwal == nil && !cfg.NewCluster:
   304→		c, err = bootstrapExistingClusterNoWAL(cfg, prt)
   305→	case bwal == nil && cfg.NewCluster:
   306→		c, err = bootstrapNewClusterNoWAL(cfg, prt)
   307→	case bwal != nil && bwal.haveWAL:
   308→		c, err = bootstrapClusterWithWAL(cfg, bwal.meta)
   309→	default:
   310→		return nil, fmt.Errorf("unsupported bootstrap config")
   311→	}
   312→	if err != nil {
   313→		return nil, err
   314→	}
   315→	return c, nil
   316→}
