   350→func bootstrapNewClusterNoWAL(cfg config.ServerConfig, prt http.RoundTripper) (*bootstrappedCluster, error) {
   351→	if err := cfg.VerifyBootstrap(); err != nil {
   352→		return nil, err
   353→	}
   354→	cl, err := membership.NewClusterFromURLsMap(cfg.Logger, cfg.InitialClusterToken, cfg.InitialPeerURLsMap, membership.WithMaxLearners(cfg.MaxLearners))
   355→	if err != nil {
   356→		return nil, err
   357→	}
   358→	m := cl.MemberByName(cfg.Name)
   359→	if isMemberBootstrapped(cfg.Logger, cl, cfg.Name, prt, cfg.BootstrapTimeoutEffective()) {
   360→		return nil, fmt.Errorf("member %s has already been bootstrapped", m.ID)
   361→	}
   362→	if cfg.ShouldDiscover() {
   363→		cfg.Logger.Info("Bootstrapping cluster using v3 discovery.")
   364→		str, err := v3discovery.JoinCluster(cfg.Logger, &cfg.DiscoveryCfg, m.ID, cfg.InitialPeerURLsMap.String())
   365→		if err != nil {
   366→			return nil, &servererrors.DiscoveryError{Op: "join", Err: err}
   367→		}
   368→		var urlsmap types.URLsMap
   369→		urlsmap, err = types.NewURLsMap(str)
   370→		if err != nil {
   371→			return nil, err
   372→		}
   373→		if config.CheckDuplicateURL(urlsmap) {
   374→			return nil, fmt.Errorf("discovery cluster %s has duplicate url", urlsmap)
   375→		}
   376→		if cl, err = membership.NewClusterFromURLsMap(cfg.Logger, cfg.InitialClusterToken, urlsmap, membership.WithMaxLearners(cfg.MaxLearners)); err != nil {
   377→			return nil, err
   378→		}
   379→	}
   380→	return &bootstrappedCluster{
   381→		remotes: nil,
   382→		cl:      cl,
   383→		nodeID:  m.ID,
   384→	}, nil
   385→}
